('01000000-0000-4000-8000-0000000004c4', 'ui_become_consultant_lead', '*', '{"label":{"tr":"Binlerce ruhsal yolculuğa rehberlik edin, uzmanlığınızı markalaştırın ve kendi kutsal çalışma alanınızı yönetin.","en":"Guide thousands of spiritual journeys, brand your expertise and manage your own sacred workspace.","de":"Begleiten Sie Tausende von spirituellen Reisen, markieren Sie Ihr Fachwissen und verwalten Sie Ihren eigenen heiligen Arbeitsbereich."}}'),
('01000000-0000-4000-8000-0000000004c5', 'ui_become_consultant_benefit1_title', '*', '{"label":{"tr":"Seçkin Kitle","en":"Elite Audience","de":"Elite-Publikum"}}'),
('01000000-0000-4000-8000-0000000004c6', 'ui_become_consultant_benefit1_desc', '*', '{"label":{"tr":"Bilinçli ve derinlik arayan binlerce aktif kullanıcıya anında erişim sağlayın.","en":"Get instant access to thousands of active, conscious users seeking depth.","de":"Erhalten Sie sofortigen Zugang zu Tausenden aktiver, bewusster Benutzer, die Tiefe suchen."}}'),
('01000000-0000-4000-8000-0000000004c7', 'ui_become_consultant_benefit2_title', '*', '{"label":{"tr":"Özgür Takvim","en":"Free Calendar","de":"Freier Kalender"}}'),
('01000000-0000-4000-8000-0000000004c8', 'ui_become_consultant_benefit2_desc', '*', '{"label":{"tr":"Kendi zamanınızı siz belirleyin; dilediğiniz yerden, dilediğiniz vakitte danışmanlık verin.","en":"Set your own time; consult from anywhere, anytime.","de":"Bestimmen Sie Ihre eigene Zeit; beraten Sie von überall und jederzeit."}}'),
('01000000-0000-4000-8000-0000000004c9', 'ui_become_consultant_benefit3_title', '*', '{"label":{"tr":"Lider Konum","en":"Leading Position","de":"Führende Position"}}'),
('01000000-0000-4000-8000-0000000004ca', 'ui_become_consultant_benefit3_desc', '*', '{"label":{"tr":"Modern astrolojinin öncü platformunda uzmanlığınızı elit bir marka altında tescilleyin.","en":"Register your expertise under an elite brand on the leading platform of modern astrology.","de":"Registrieren Sie Ihr Fachwissen unter einer Elite-Marke auf der führenden Plattform der modernen Astrologie."}}'),
