('01000000-0000-4000-8000-0000000004d9', 'ui_become_consultant_form_bio_hint', '*', '{"label":{"tr":"Kendinizi, yaklaşımınızı ve danışana ne sunduğunuzu anlatın. İletişim bilgisi/dış link yazmayın. En az 150 karakter önerilir.","en":"Describe yourself, your approach and what you offer to the client. Do not write contact information/external links. At least 150 characters recommended.","de":"Beschreiben Sie sich selbst, Ihren Ansatz und was Sie dem Kunden anbieten. Keine Kontaktinformationen/externe Links. Mindestens 150 Zeichen empfohlen."}}'),
('01000000-0000-4000-8000-0000000004da', 'ui_become_consultant_form_bio_placeholder', '*', '{"label":{"tr":"Uzmanlığınız, yaklaşımınız ve ruhsal rehberlik tarzınızdan bahsedin...","en":"Talk about your expertise, approach and style of spiritual guidance...","de":"Sprechen Sie über Ihr Fachwissen, Ihren Ansatz und Ihren Stil der spirituellen Führung..."}}'),
('01000000-0000-4000-8000-0000000004db', 'ui_become_consultant_form_avatar_note', '*', '{"label":{"tr":"* Profil fotoğrafınızı başvurunuz onaylandıktan sonra panel üzerinden ekleyeceksiniz.","en":"* You will add your profile photo through the panel after your application is approved.","de":"* Sie werden Ihr Profilfoto über das Panel hinzufügen, nachdem Ihre Bewerbung genehmigt wurde."}}'),
