('01000000-0000-4000-8000-0000000004e8', 'ui_become_consultant_success_title', '*', '{"label":{"tr":"Başvurunuz Gökyüzüne Ulaştı!","en":"Your Application Reached the Skies!","de":"Ihre Bewerbung hat den Himmel erreicht!"}}'),
('01000000-0000-4000-8000-0000000004e9', 'ui_become_consultant_success_desc', '*', '{"label":{"tr":"Değerli vaktinizi ayırdığınız için teşekkür ederiz. Başvurunuz uzman küratör ekibimiz tarafından özenle incelenecek ve en kısa sürede sizinle iletişime geçeceğiz.","en":"Thank you for your valuable time. Your application will be carefully reviewed by our expert curator team and we will contact you as soon as possible.","de":"Vielen Dank für Ihre wertvolle Zeit. Ihre Bewerbung wird von unserem Experten-Kurator-Team sorgfältig geprüft und wir werden uns so schnell wie möglich bei Ihnen melden."}}'),
